export const BASE_URL = "https://www.sensoramadesign.com";

export const langPath: Record<Lang, string> = { pt: "", en: "/en", es: "/es" };

export function casesPath(lang: Lang): string {
  return `${langPath[lang]}/cases`;
}

export function casePath(lang: Lang, slug: string): string {
  return `${langPath[lang]}/cases/${slug}`;
}

export function getAllCaseSlugs(): string[] {
  return CASES.filter((c) => !c.hidden).map((c) => c.slug);
}

export function getVisibleCases(): CaseRecord[] {
  return CASES.filter((c) => !c.hidden);
}

export function getCasesByIndustry(industry: Industry | "all"): CaseRecord[] {
  if (industry === "all") return getVisibleCases();
  return getVisibleCases().filter((c) => c.industry === industry);
}
